) VALUES (
      #{ses.gateCd}
    , #{ses.companyCd}
    , #{AI_INQ_NO}
    , #{ITEM_CD}
    , #{ITEM_DESC}
    , #{ITEM_SPEC}
    , #{MIN_PRICE}
    , #{AVG_PRICE}
    , #{CONFIDENCE}
    , #{ANALYSIS_RESULT}
